export function closeProfileEdit(event) {
    if (event && event.target !== event.currentTarget) return;
    state.showProfileEdit = false;
    render();
}

window.closeProfileEdit = closeProfileEdit;

export function saveProfile() {
    const user = users.find(u => u.id === state.currentUser.id);
    if (user) {
        user.name = state.currentUser.name;
        user.email = state.currentUser.email;
        user.gender = state.currentUser.gender;
        user.theme = state.currentUser.theme;
    }
    if (state.currentUser.theme) {
        ThemeManager.setTheme(state.currentUser.theme);
    }
    state.showProfileEdit = false;
    showToast('Профиль сохранён');
    render();
}

window.saveProfile = saveProfile;

